def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            if capacity == 0 and item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        factor = 1.0
        penalty = 0.0
        decay = 1.0
        extra_penalties = 0.0
        complex_sum = 0.0
        prime_factors = [2,3,5,7,11]
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 4:
            for k in range(1, 10):
                power = ratio ** (2*k)
                prime_factor = prime_factors[k % len(prime_factors)]
                penalty += power / (k**2 + prime_factor)
            for j in range(1, 6):
                decay *= (1 - (1 / (ratio + j**2 + 1)))
            score = (ratio ** 6) / 5 + penalty
            if item > capacity * 5:
                score *= 4
            else:
                score *= 3
            priorities[i] = score * decay
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                prime_factor = prime_factors[x % len(prime_factors)]
                complex_sum += sign * (ratio ** x) / (x + prime_factor)
            for y in range(1, 7):
                decay *= (1 - 1 / (y + ratio**1.5 + prime_factors[y % len(prime_factors)]))
            priorities[i] = abs(complex_sum) * decay * 15
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                prime_factor = prime_factors[p % len(prime_factors)]
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * prime_factor)
                else:
                    temp -= (ratio ** p) / (p * (prime_factor + 1))
            multiplier = 30 if ratio < 2.5 else 20 if ratio < 2.8 else 12
            score = abs(temp) * multiplier
            if ratio > 2.9:
                extra = 0
                for m in range(1, 8):
                    pf = prime_factors[m % len(prime_factors)]
                    extra += (ratio ** m) / (m + pf)
                score += extra * 3
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 20):
                pf = prime_factors[p % len(prime_factors)]
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * pf)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * (pf + 2))
                else:
                    temp_score += (ratio ** p) / (p * (pf + 1))
            if ratio < 1.3:
                multiplier = 40
            elif ratio < 1.7:
                multiplier = 25
            else:
                multiplier = 18
            score = abs(temp_score) * multiplier
            if 1.8 < ratio < 2:
                extra_penalties = 0
                for n in range(1, 10):
                    pf = prime_factors[n % len(prime_factors)]
                    extra_penalties += (ratio ** n) / (n + pf)
                score += extra_penalties * 2.5
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 25):
                pf = prime_factors[p % len(prime_factors)]
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * pf)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * (pf + 3))
                elif p % 3 == 0:
                    temp_score += (ratio ** p) / (p * (pf + 2))
                else:
                    temp_score -= (ratio ** p) / (p * (pf + 1))
            if ratio < 0.1:
                multiplier = 35
            elif ratio < 0.3:
                multiplier = 25
            elif ratio < 0.5:
                multiplier = 18
            elif ratio < 0.7:
                multiplier = 12
            else:
                multiplier = 8
            score = abs(temp_score) * multiplier
            if 0.75 < ratio < 1:
                extra_penalties = 0
                for n in range(1, 15):
                    pf = prime_factors[n % len(prime_factors)]
                    extra_penalties += (ratio ** n) / (n + pf)
                score += extra_penalties * 3
            priorities[i] = score
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if priorities[i] != np.inf:
            scale_factor = 1.0
            for z in range(1, 6):
                if (bins[i] + z) != 0:
                    scale_factor *= (1 + (z**1.5) / (bins[i] + z))
            priorities[i] *= scale_factor
        if np.isnan(priorities[i]) or priorities[i] < 0:
            priorities[i] = np.inf
    mean_priority = np.mean(priorities[np.isfinite(priorities)])
    std_priority = np.std(priorities[np.isfinite(priorities)])
    for i in range(len(priorities)):
        if priorities[i] != np.inf:
            if priorities[i] > mean_priority + 3 * std_priority:
                priorities[i] = mean_priority + 3 * std_priority
            elif priorities[i] < mean_priority - 3 * std_priority:
                priorities[i] = mean_priority - 3 * std_priority
    return priorities
